parameters.jsCode:
// Get input data and rules
const input = $('Receive Data').first().json.body;
const defaults = $('Set Default Rules').first().json;

const data = input.data;
const rules = input.rules || defaults.rules || {};

// Validate input
if (!data || !Array.isArray(data)) {
  return [{
    json: {
      valid: false,
      error: 'Invalid input: "data" must be an array of objects.',
      summary: { totalRows: 0, validRows: 0, invalidRows: 0, totalErrors: 1 },
      errors: []
    }
  }];
}

if (!rules || Object.keys(rules).length === 0) {
  return [{
    json: {
      valid: false,
      error: 'No validation rules provided. Send rules in the request body or configure them in the Set Default Rules node.',
      summary: { totalRows: data.length, validRows: 0, invalidRows: 0, totalErrors: 1 },
      errors: []
    }
  }];
}

// Validation helpers
const isPresent = (v) => v !== null && v !== undefined && v !== '';
const isEmail = (v) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(v));
const isNumber = (v) => !isNaN(Number(v)) && String(v).trim() !== '';
const isUrl = (v) => /^https?:\/\/.+\..+/.test(String(v));
const isBool = (v) => ['true','false','0','1','yes','no'].includes(String(v).toLowerCase());

function isValidDate(v, fmt) {
  if (fmt === 'YYYY-MM-DD') return /^\d{4}-\d{2}-\d{2}$/.test(v);
  if (fmt === 'DD.MM.YYYY') return /^\d{2}\.\d{2}\.\d{4}$/.test(v);
  if (fmt === 'MM/DD/YYYY') return /^\d{2}\/\d{2}\/\d{4}$/.test(v);
  return !isNaN(Date.parse(v));
}

const errors = [];
let validRows = 0;
let invalidRows = 0;

for (let i = 0; i < data.length; i++) {
  const row = data[i];
  let rowHasError = false;

  for (const [field, fr] of Object.entries(rules)) {
    const value = row[field];

    // Required check
    if (fr.required && !isPresent(value)) {
      errors.push({
        row: i + 1, field, value: value ?? null,
        rule: 'required',
        message: `Field '${field}' is required`
      });
      rowHasError = true;
      continue;
    }

    // Skip further checks if empty and not required
    if (!isPresent(value)) continue;

    // Type checks
    if (fr.type) {
      let typeValid = true;
      let typeLabel = fr.type;

      switch (fr.type) {
        case 'string':
          typeValid = typeof value === 'string';
          break;
        case 'number':
          typeValid = isNumber(value);
          break;
        case 'email':
          typeValid = isEmail(value);
          break;
        case 'url':
          typeValid = isUrl(value);
          break;
        case 'boolean':
          typeValid = isBool(value);
          break;
        case 'date':
          typeValid = isValidDate(value, fr.dateFormat);
          typeLabel = fr.dateFormat ? `date (${fr.dateFormat})` : 'date';
          break;
      }

      if (!typeValid) {
        errors.push({
          row: i + 1, field, value,
          rule: `type:${fr.type}`,
          message: `Field '${field}' must be a valid ${typeLabel}`
        });
        rowHasError = true;
      }
    }

    // String length checks
    if (fr.minLength !== undefined && String(value).length < fr.minLength) {
      errors.push({
        row: i + 1, field, value,
        rule: 'minLength',
        message: `Field '${field}' must be at least ${fr.minLength} characters`
      });
      rowHasError = true;
    }

    if (fr.maxLength !== undefined && String(value).length > fr.maxLength) {
      errors.push({
        row: i + 1, field, value,
        rule: 'maxLength',
        message: `Field '${field}' must be at most ${fr.maxLength} characters`
      });
      rowHasError = true;
    }

    // Numeric range checks
    if (fr.min !== undefined && isNumber(value) && Number(value) < fr.min) {
      errors.push({
        row: i + 1, field, value,
        rule: 'min',
        message: `Field '${field}' must be >= ${fr.min}`
      });
      rowHasError = true;
    }

    if (fr.max !== undefined && isNumber(value) && Number(value) > fr.max) {
      errors.push({
        row: i + 1, field, value,
        rule: 'max',
        message: `Field '${field}' must be <= ${fr.max}`
      });
      rowHasError = true;
    }

    // Regex check
    if (fr.regex && !new RegExp(fr.regex).test(String(value))) {
      errors.push({
        row: i + 1, field, value,
        rule: 'regex',
        message: `Field '${field}' does not match pattern: ${fr.regex}`
      });
      rowHasError = true;
    }

    // Enum check
    if (fr.enum && !fr.enum.includes(value)) {
      errors.push({
        row: i + 1, field, value,
        rule: 'enum',
        message: `Field '${field}' must be one of: ${fr.enum.join(', ')}`
      });
      rowHasError = true;
    }
  }

  if (rowHasError) invalidRows++;
  else validRows++;
}

return [{
  json: {
    valid: errors.length === 0,
    summary: {
      totalRows: data.length,
      validRows,
      invalidRows,
      totalErrors: errors.length
    },
    errors
  }
}];
